module rc_oscillator_counter(  
    input wire reset_signal,  
    input wire rst,  
    output reg [3:0] count  
);  
    always @(posedge reset_signal or posedge rst) begin  
        if (rst)  
            count <= 4'b0000;  
        else  
            count <= count + 1;  
    end  
endmodule
